mod.talkaction:
domodlib('exppotion')
if (getPlayerStorageValue(cid, exp_info.storage[1]) - os.time() > 0) then
	return doPlayerSendTextMessage(cid, MESSAGE_STATUS_CONSOLE_ORANGE, "Você tem "..convertTimeString(getPlayerStorageValue(cid, exp_info.storage[1]) - os.time()).." de de Pergaminho do EXP.")
elseif (getPlayerStorageValue(cid, exp_info.storage[2]) - os.time() > 0) then
	return doPlayerSendTextMessage(cid, MESSAGE_STATUS_CONSOLE_ORANGE, "Você tem "..convertTimeString(getPlayerStorageValue(cid, exp_info.storage[2]) - os.time()).." Exp Potion.")
else
	return doPlayerSendTextMessage(cid, MESSAGE_STATUS_CONSOLE_ORANGE, "Você não possui Exp Potion ou Pergaminho do EXP ativo no momento.")
end
